import{_ as a,o as t,c as i,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Multiple Goal ID Support","description":"","frontmatter":{"title":"Multiple Goal ID Support","slug":"multiple-goal-id-support"},"headers":[],"relativePath":"marketer-hub/multiple-goal-id-support.md","filePath":"marketer-hub/multiple-goal-id-support.md"}'),s={name:"marketer-hub/multiple-goal-id-support.md"};function r(o,e,p,l,h,d){return t(),i("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch provides the ability to send different Postbacks for an in-app or pre-defined event depending on the multiple Goal IDs specified in the tracking link.</p><p>This feature supports networks using HasOffers, CAKE or any other network that wants to receive different in-app event postbacks for a single SDK in-app event.</p><p>On the Integrated Partners page of Branch&#39;s dashboard clients must map each of their Events to their preferred dynamic Event Postback for each Goal ID.</p><p>This enables the integrated ad networks to open multiple campaigns with a separate dynamic event tag (example: HasOffers calls this a &quot;goal_id&quot;) for each campaign. The dynamic event tags are then passed to the ad network in the Postback based on the value that was placed in the click URL.</p><h2 id="branch-tracking-link-example" tabindex="-1">Branch Tracking Link Example <a class="header-anchor" href="#branch-tracking-link-example" aria-label="Permalink to &quot;Branch Tracking Link Example&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://branchster.app.link/bKzQX2KCcS?%243p=partner_id&amp;~click_id={clickid}&amp;goalid_1={XXX}&amp;goalid_2={YYY}&amp;goalid_3={ZZZ}</span></span></code></pre></div><p>The advertiser must map all of the Goal_IDs in the Postback events section under Postback Config (see below) according to the network&#39;s instructions.</p><p>In the example below, the HasOffers Postbacks are mapped as follows:</p><ul><li>OPEN is mapped with <strong>goalid_1</strong></li><li>PURCHASE is mapped with <strong>goalid_2</strong></li><li>PAGEVIEW is mapped with <strong>goalid_3</strong></li></ul><p>This means that when a user triggers an OPEN event via the tracking link above, Branch returns the relevant value (XXX) and sends it in the Postback URL.</p><p>If the same or a different user then completes a PURCHASE event, Branch again returns to the tracking link and dynamically populates the goal_id with the relevant value (in this case YYY) and sends it in the postback. The same logic applies to PAGEVIEW and other Events mapped to Goal IDs on the Branch Dashboard.</p>',12)])])}const m=a(s,[["render",r]]);export{u as __pageData,m as default};
